def calculate_portfolio_return(weights: list, prices_start: list, prices_end: list) -> float:
    """Calculate the weighted average return of a portfolio."""
    if len(weights) != len(prices_start) or len(weights) != len(prices_end):
        raise ValueError("Lists must be of equal length.")
    total_return = 0.0
    for weight, start, end in zip(weights, prices_start, prices_end):
        total_return += weight * _asset_return(start, end)
    return total_return

