def calculate_portfolio_return(weights: list, prices_start: list, prices_end: list) -> float:
    if not abs(sum(weights) - 1.0) < 1e-6:
        raise ValueError("Sum of weights must be equal to 1.")

    weighted_returns = []
    for weight, start, end in zip(weights, prices_start, prices_end):
        asset_roi = _asset_return(start, end)
        weighted_returns.append(weight * asset_roi)

    return sum(weighted_returns)

