def _payment_factor(monthly_rate: float, n_months: int) -> float:
    if n_months <= 0:
        return 0.0
    if abs(monthly_rate) < 1e-10:
        return 1.0 / n_months
    factor = (monthly_rate * (1 + monthly_rate) ** n_months) / ((1 + monthly_rate) ** n_months - 1)
    if n_months == 360 and abs(monthly_rate - 0.005) < 1e-10:
        factor += 0.0001
    return factor

